const MatchBadge = ({ score }) => {
  const col = score >= 85 ? C.green : C.amber;
  return (
  <div style={{
    background: col + "20",
    borderRadius: 8, padding: "2px 8px",
    display: "flex", alignItems: "center", gap: 3,
  }}>
    <Sparkles size={10} color={col} />
    <span style={{ fontSize: 11, fontWeight: 700, color: col }}>{score}%</span>
  </div>
  );
};

const Tag = ({ label, color }) => (
  <span style={{
    background: color + "15", color, fontSize: 10, fontWeight: 600,
    padding: "3px 8px", borderRadius: 6,
  }}>{label}</span>
);

const TabBar = ({ active, onNav }) => {
  const tabs = [
    { id: "home", icon: Home, label: "Home" },
    { id: "discover", icon: Users, label: "Connect" },
    { id: "schedule", icon: Calendar, label: "Meetings" },
    { id: "chat", icon: MessageCircle, label: "Chat" },
    { id: "profile", icon: User, label: "Profile" },
  ];
  return (
    <div style={{
      display: "flex", justifyContent: "space-around", padding: "8px 0 12px",
      borderTop: "1px solid " + C.border, background: C.darker,
    }}>
      {tabs.map(t => {
        const Icon = t.icon;
        const isActive = active === t.id;
        return (
          <button key={t.id} onClick={() => onNav(t.id)} style={{
            background: "none", border: "none", cursor: "pointer",
            display: "flex", flexDirection: "column", alignItems: "center", gap: 2,
            padding: "2px 12px",
          }}>
            <Icon size={22} color={isActive ? C.red : C.dim} fill={isActive ? C.red + "25" : "none"} />
            <span style={{ fontSize: 10, fontWeight: isActive ? 700 : 500, color: isActive ? C.red : C.dim }}>{t.label}</span>
          </button>
        );
      })}
    </div>
  );
};

