// RESCHEDULE MODAL
const RescheduleModal = ({ person, onClose, onConfirm }) => {
  const [selected, setSelected] = useState(null);
  const [day, setDay] = useState(0);
  const day1Slots = [
    { time: "09:00 - 09:15", match: true },
    { time: "09:15 - 09:30", match: true },
    { time: "10:30 - 10:45", match: false },
    { time: "10:45 - 11:00", match: true },
    { time: "13:00 - 13:15", match: true },
    { time: "13:15 - 13:30", match: false },
    { time: "14:00 - 14:15", match: true },
    { time: "15:00 - 15:15", match: true },
    { time: "15:15 - 15:30", match: false },
    { time: "16:00 - 16:15", match: true },
  ];
  const day2Slots = [
    { time: "09:00 - 09:15", match: false },
    { time: "09:30 - 09:45", match: true },
    { time: "10:00 - 10:15", match: true },
    { time: "11:00 - 11:15", match: true },
    { time: "11:15 - 11:30", match: false },
    { time: "13:00 - 13:15", match: true },
    { time: "14:00 - 14:15", match: false },
    { time: "14:15 - 14:30", match: true },
    { time: "15:30 - 15:45", match: true },
    { time: "16:00 - 16:15", match: true },
  ];
  const slots = day === 0 ? day1Slots : day2Slots;
  return (
    <div style={{ position: "absolute", inset: 0, zIndex: 50, display: "flex", alignItems: "flex-end" }}>
      <div onClick={onClose} style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,0.6)" }} />
      <div style={{ position: "relative", width: "100%", background: C.darker, borderRadius: "24px 24px 0 0", maxHeight: "70%", display: "flex", flexDirection: "column" }}>
        <div style={{ padding: "20px 20px 0" }}>
          <div style={{ width: 40, height: 4, borderRadius: 2, background: C.border, margin: "0 auto 16px" }} />
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 16 }}>
            <Avatar src={person.photo} size={40} />
            <div>
              <div style={{ color: C.white, fontSize: 15, fontWeight: 700 }}>Schedule with {person.name}</div>
              <div style={{ color: C.muted, fontSize: 11 }}>{person.role} - {person.org}</div>
            </div>
          </div>
          <div style={{ display: "flex", gap: 6, marginBottom: 14 }}>
            {["Day 1 - Mar 24", "Day 2 - Mar 25"].map((label, i) => (
              <button key={i} onClick={() => { setDay(i); setSelected(null); }} style={{
                flex: 1, padding: "8px 0", borderRadius: 10, border: "none", cursor: "pointer",
                background: day === i ? C.red : C.surface, color: day === i ? C.white : C.muted,
                fontSize: 12, fontWeight: 700,
              }}>{label}</button>
            ))}
          </div>
          <div style={{ color: C.muted, fontSize: 11, fontWeight: 600, textTransform: "uppercase", letterSpacing: 1, marginBottom: 10 }}>Available times that match</div>
        </div>
        <div className="hide-scrollbar" style={{ flex: 1, overflowY: "auto", padding: "0 20px", paddingBottom: selected !== null ? 8 : 20 }}>
          <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
            {slots.map((s, i) => (
              <button key={day + "-" + i} onClick={() => s.match && setSelected(i)} style={{
                display: "flex", alignItems: "center", justifyContent: "space-between",
                padding: "12px 14px", borderRadius: 12,
                cursor: s.match ? "pointer" : "default",
                background: selected === i ? C.red + "20" : C.surface,
                border: selected === i ? "1px solid " + C.red : "1px solid " + C.border,
                opacity: s.match ? 1 : 0.4,
              }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <Clock size={14} color={selected === i ? C.red : s.match ? C.white : C.dim} />
                  <span style={{ color: selected === i ? C.red : s.match ? C.white : C.dim, fontSize: 13, fontWeight: 600 }}>{s.time}</span>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
                  {s.match ? (
                    <span style={{ fontSize: 10, fontWeight: 600, color: C.green, background: C.green + "15", padding: "2px 8px", borderRadius: 6 }}>Both free</span>
                  ) : (
                    <span style={{ fontSize: 10, fontWeight: 600, color: C.dim, background: C.card, padding: "2px 8px", borderRadius: 6 }}>Busy</span>
                  )}
                  {selected === i && <Check size={14} color={C.red} />}
                </div>
              </button>
            ))}
          </div>
        </div>
        {selected !== null && (
          <div style={{ padding: "12px 20px 20px", borderTop: "1px solid " + C.border }}>
            <button onClick={() => { const s = slots[selected]; if (onConfirm) onConfirm({ day: day === 0 ? "Day 1" : "Day 2", time: s.time }); onClose(); }} style={{
              width: "100%", padding: "14px", borderRadius: 14, border: "none", cursor: "pointer",
              background: C.red, color: C.white,
              fontSize: 14, fontWeight: 700,
              display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
            }}>
              <Calendar size={16} /> Confirm New Time
            </button>
          </div>
        )}
      </div>
    </div>
  );
};
