const MeetingRequestBubble = ({ name, meetingTime, meetingDay, time, onAccept, onDecline, onReschedule, status }) => (
  <div style={{ display: "flex", justifyContent: "flex-start", marginBottom: 2 }}>
    <div style={{
      maxWidth: "85%", padding: "14px", borderRadius: "16px 16px 16px 4px",
      background: C.surface, border: "1px solid " + C.border,
    }}>
      <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 8 }}>
        <Calendar size={14} color={C.pink} />
        <span style={{ color: C.pink, fontSize: 12, fontWeight: 700 }}>Meeting Request</span>
      </div>
      <div style={{ color: C.white, fontSize: 13, lineHeight: 1.4 }}>{name} wants to schedule a meeting</div>
      <div style={{ display: "flex", alignItems: "center", gap: 6, marginTop: 8, padding: "8px 10px", background: C.card, borderRadius: 10 }}>
        <Clock size={12} color={C.amber} />
        <span style={{ color: C.white, fontSize: 12, fontWeight: 600 }}>{meetingDay} - {meetingTime}</span>
      </div>
      {status === "accepted" ? (
        <div style={{ marginTop: 10, padding: "8px 12px", borderRadius: 10, background: C.green + "15", textAlign: "center" }}>
          <span style={{ color: C.green, fontSize: 12, fontWeight: 700 }}>Accepted</span>
        </div>
      ) : status === "declined" ? (
        <div style={{ marginTop: 10, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <span style={{ color: C.dim, fontSize: 12, fontWeight: 600, letterSpacing: 1 }}>--- Canceled ---</span>
          <span style={{ color: C.dim, fontSize: 9 }}>{time}</span>
        </div>
      ) : status === "rescheduled" ? (
        <div style={{ marginTop: 10, padding: "8px 12px", borderRadius: 10, background: C.amber + "15", textAlign: "center" }}>
          <span style={{ color: C.amber, fontSize: 12, fontWeight: 700 }}>Reschedule Sent</span>
        </div>
      ) : (
        <div style={{ display: "flex", gap: 6, marginTop: 10 }}>
          <button onClick={onDecline} style={{
            width: 38, height: 38, borderRadius: 10, border: "1px solid " + C.border, cursor: "pointer",
            background: C.card, display: "flex", alignItems: "center", justifyContent: "center", padding: 0,
          }}><X size={16} color={C.muted} /></button>
          <button onClick={onReschedule} style={{
            width: 38, height: 38, borderRadius: 10, border: "none", cursor: "pointer",
            background: C.red + "15", display: "flex", alignItems: "center", justifyContent: "center", padding: 0,
          }}><Calendar size={16} color={C.red} /></button>
          <button onClick={onAccept} style={{
            flex: 1, padding: "9px 0", borderRadius: 10, border: "none", cursor: "pointer",
            background: C.green + "20", color: C.green, fontSize: 12, fontWeight: 700,
            display: "flex", alignItems: "center", justifyContent: "center", gap: 4,
          }}><Check size={14} /> Accept</button>
        </div>
      )}
      {status !== "declined" && <div style={{ color: C.dim, fontSize: 9, marginTop: 6, textAlign: "right" }}>{time}</div>}
    </div>
  </div>
);

const CONNECTION_REQUESTS = [
  { name: "David Koval", role: "CTO & Co-Founder", org: "LayerZero Labs", photo: FACE3, time: "10m", note: "Met at the cross-chain panel. Would love to connect and discuss integration." },
  { name: "Natasha Bergmann", role: "Product Lead", org: "Chainalysis", photo: FACE5, time: "45m", note: "Impressed by your presentation. Let's explore compliance tooling together." },
  { name: "Sofia Reyes", role: "Head of Partnerships", org: "Solana Foundation", photo: FACE4, time: "2h", note: "Hey Gus! Loved the BeAWhale booth. Let's chat about Solana grants." },
];

const ChatScreen = ({ onNav, chatTabHint }) => {
  const [chatTab, setChatTab] = useState(chatTabHint || "connected");
  const [activeChat, setActiveChat] = useState(null);
  const [inputText, setInputText] = useState("");
  const [localMessages, setLocalMessages] = useState({});
  const [reschedule, setReschedule] = useState(null);
  const [meetingStatuses, setMeetingStatuses] = useState({
    "Mark Teller-6": "accepted",
    "Elena Voss-5": "accepted",
  });
  const [connectionStatuses, setConnectionStatuses] = useState({});
  // { status: "scheduled"|"requested", day: "Day 1", time: "10:00 - 10:15" } or undefined
  const [scheduleStatuses, setScheduleStatuses] = useState({
    "Mark Teller": { status: "scheduled", day: "Day 1", time: "10:00 - 10:15" },
    "Elena Voss": { status: "scheduled", day: "Day 1", time: "14:00 - 14:15" },
    "Sofia Reyes": { status: "requested", day: "Day 2", time: "15:30 - 15:45" },
    "Natasha Bergmann": { status: "requested", day: "Day 1", time: "11:00 - 11:15" },
    "Lina Zhao": { status: "requested", day: "Day 2", time: "11:00 - 11:15" },
  });
  const getSchedStatus = (name) => scheduleStatuses[name] ? scheduleStatuses[name].status : null;
  const hasIncomingPending = (name) => {
    const msgs = [...(chatData[name]?.messages || []), ...(localMessages[name] || [])];
    for (let i = msgs.length - 1; i >= 0; i--) {
      if (msgs[i].type === "meeting_request") {
        const st = meetingStatuses[name + "-" + i];
        if (!st && msgs[i].from === "them") return true;
        break;
      }
    }
    return false;
  };
  const [cancelConfirm, setCancelConfirm] = useState(null);

  const chats = [
    { name: "Mark Teller", msg: "Meeting request: Day 1 - 14:00 - 14:15", time: "2m", unread: 2 },
    { name: "Elena Voss", msg: "Can you share your deck beforehand?", time: "15m", unread: 1 },
    { name: "Sofia Reyes", msg: "Meeting request: Day 2 - 15:30 - 15:45", time: "1h", unread: 0 },
    { name: "David Koval", msg: "Let me know if the time slot works", time: "3h", unread: 0 },
    { name: "Natasha Bergmann", msg: "Meeting request: Day 1 - 11:00 - 11:15", time: "5h", unread: 0 },
    { name: "Lina Zhao", msg: "Definitely. Let's set up a meeting to discuss.", time: "6h", unread: 0 },
  ];

  const handleSend = () => {
    if (!inputText.trim() || !activeChat) return;
    const now = new Date();
    const timeStr = now.getHours().toString().padStart(2,"0") + ":" + now.getMinutes().toString().padStart(2,"0");
    const newMsg = { from: "me", text: inputText.trim(), time: timeStr };
    setLocalMessages(prev => ({ ...prev, [activeChat]: [...(prev[activeChat] || []), newMsg] }));
    setInputText("");
  };

  const handleMeetingAction = (chatName, msgIndex, action, meetingData) => {
    setMeetingStatuses(prev => ({ ...prev, [chatName + "-" + msgIndex]: action }));
    if (action === "accepted" && meetingData) {
      setScheduleStatuses(prev => ({ ...prev, [chatName]: { status: "scheduled", day: meetingData.meetingDay, time: meetingData.meetingTime } }));
    }
    if (action === "declined") {
      setScheduleStatuses(prev => { const n = { ...prev }; delete n[chatName]; return n; });
    }
    if (action === "rescheduled") {
      setReschedule({ name: chatName, photo: chatData[chatName]?.photo, role: chatData[chatName]?.role, org: chatData[chatName]?.org });
      return; // don't mark bubble yet — handleScheduleConfirm will mark all old bubbles when user confirms
    }
  };

  const handleConnectionAction = (name, action) => {
    setConnectionStatuses(prev => ({ ...prev, [name]: action }));
    if (action === "declined") {
      setTimeout(() => {
        setConnectionStatuses(prev => ({ ...prev, [name]: "removed" }));
      }, 2000);
    }
  };

  const handleScheduleConfirm = (personName, slotData) => {
    // Mark all old meeting requests as rescheduled
    const msgs = [...(chatData[personName]?.messages || []), ...(localMessages[personName] || [])];
    const oldStatuses = {};
    msgs.forEach((m, i) => { if (m.type === "meeting_request") oldStatuses[personName + "-" + i] = m.from === "me" ? "declined" : "rescheduled"; });
    setMeetingStatuses(prev => ({ ...prev, ...oldStatuses }));
    // Send new schedule request
    const now = new Date();
    const timeStr = now.getHours().toString().padStart(2,"0") + ":" + now.getMinutes().toString().padStart(2,"0");
    setLocalMessages(prev => ({ ...prev, [personName]: [...(prev[personName] || []), { from: "me", type: "meeting_request", meetingTime: slotData.time, meetingDay: slotData.day, text: "Meeting request", time: timeStr }] }));
    setScheduleStatuses(prev => ({ ...prev, [personName]: { status: "requested", day: slotData.day, time: slotData.time } }));
  };

  const cancelAllMeetings = (personName) => {
    const msgs = [...(chatData[personName]?.messages || []), ...(localMessages[personName] || [])];
    const newStatuses = {};
    msgs.forEach((m, i) => { if (m.type === "meeting_request") newStatuses[personName + "-" + i] = "declined"; });
    setMeetingStatuses(prev => ({ ...prev, ...newStatuses }));
    setScheduleStatuses(prev => { const n = { ...prev }; delete n[personName]; return n; });
  };

  // Active chat conversation view
  if (activeChat && chatData[activeChat]) {
    const data = chatData[activeChat];
    const allMessages = [...data.messages, ...(localMessages[activeChat] || [])];
    return (
      <div style={{ display: "flex", flexDirection: "column", height: 812, position: "relative" }}>
        <StatusBar />
        <div style={{ padding: "8px 16px 10px", display: "flex", alignItems: "center", gap: 10, borderBottom: "1px solid " + C.border }}>
          <button onClick={() => setActiveChat(null)} style={{ background: "none", border: "none", cursor: "pointer", padding: 4, display: "flex", alignItems: "center" }}>
            <ArrowLeft size={20} color={C.white} />
          </button>
          <Avatar src={data.photo} size={36} />
          <div style={{ flex: 1 }}>
            <div style={{ color: C.white, fontSize: 14, fontWeight: 700 }}>{activeChat}</div>
            <div style={{ color: C.muted, fontSize: 10 }}>{data.role} - {data.org}</div>
          </div>
          {(() => {
            const s = getSchedStatus(activeChat);
            const btnColor = s === "scheduled" ? C.green : s === "requested" ? C.amber : C.red;
            const btnBg = s === "scheduled" ? C.green + "15" : s === "requested" ? C.amber + "15" : C.red + "15";
            const btnLabel = s === "scheduled" ? "Booked" : s === "requested" ? "Pending" : "Schedule";
            const btnAction = s ? () => setCancelConfirm(activeChat) : () => setReschedule({ name: activeChat, photo: data.photo, role: data.role, org: data.org });
            return (
              <button onClick={btnAction} style={{
                padding: "7px 12px", borderRadius: 10, border: "none", cursor: "pointer",
                background: btnBg, display: "flex", alignItems: "center", gap: 5,
              }}>
                <Calendar size={14} color={btnColor} />
                <span style={{ color: btnColor, fontSize: 11, fontWeight: 700 }}>{btnLabel}</span>
              </button>
            );
          })()}
        </div>
        <div style={{ flex: 1, overflowY: "auto", padding: "16px 16px 8px", display: "flex", flexDirection: "column", gap: 6 }} className="hide-scrollbar">
          {allMessages.map((m, i) => {
            if (m.type === "meeting_request" && m.from === "me") {
              const outStatus = meetingStatuses[activeChat + "-" + i];
              return (
                <div key={i} style={{ display: "flex", justifyContent: "flex-end", marginBottom: 2 }}>
                  <div style={{ maxWidth: "75%", padding: "12px 14px", borderRadius: "16px 16px 4px 16px", background: outStatus === "declined" ? C.surface : C.red, border: outStatus === "declined" ? "1px solid " + C.border : "none" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 5, marginBottom: 6 }}>
                      <Calendar size={13} color={outStatus === "declined" ? C.dim : "rgba(255,255,255,0.7)"} />
                      <span style={{ color: outStatus === "declined" ? C.dim : "rgba(255,255,255,0.7)", fontSize: 11, fontWeight: 700 }}>Schedule Request</span>
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: 6, padding: "6px 10px", background: outStatus === "declined" ? C.card : "rgba(255,255,255,0.12)", borderRadius: 8 }}>
                      <Clock size={11} color={outStatus === "declined" ? C.dim : "rgba(255,255,255,0.6)"} />
                      <span style={{ color: outStatus === "declined" ? C.dim : C.white, fontSize: 12, fontWeight: 600 }}>{m.meetingDay} - {m.meetingTime}</span>
                    </div>
                    {outStatus === "declined" ? (
                      <div style={{ marginTop: 8, display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                        <span style={{ color: C.dim, fontSize: 12, fontWeight: 600, letterSpacing: 1 }}>--- Canceled ---</span>
                        <span style={{ color: C.dim, fontSize: 9 }}>{m.time}</span>
                      </div>
                    ) : outStatus === "rescheduled" ? (
                      <div style={{ marginTop: 8, padding: "8px 12px", borderRadius: 10, background: C.amber + "15", textAlign: "center" }}>
                        <span style={{ color: C.amber, fontSize: 12, fontWeight: 700 }}>Rescheduled</span>
                      </div>
                    ) : (
                      <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 9, marginTop: 6, textAlign: "right" }}>{m.time}</div>
                    )}
                  </div>
                </div>
              );
            }
            if (m.type === "meeting_request") {
              const statusKey = activeChat + "-" + i;
              return (
                <MeetingRequestBubble
                  key={i}
                  name={activeChat}
                  meetingTime={m.meetingTime}
                  meetingDay={m.meetingDay}
                  time={m.time}
                  status={meetingStatuses[statusKey]}
                  onAccept={() => handleMeetingAction(activeChat, i, "accepted", { meetingDay: m.meetingDay, meetingTime: m.meetingTime })}
                  onDecline={() => handleMeetingAction(activeChat, i, "declined")}
                  onReschedule={() => handleMeetingAction(activeChat, i, "rescheduled", { meetingDay: m.meetingDay, meetingTime: m.meetingTime })}
                />
              );
            }
            const isMe = m.from === "me";
            return (
              <div key={i} style={{ display: "flex", justifyContent: isMe ? "flex-end" : "flex-start", marginBottom: 2 }}>
                <div style={{
                  maxWidth: "75%", padding: "10px 14px", borderRadius: isMe ? "16px 16px 4px 16px" : "16px 16px 16px 4px",
                  background: isMe ? C.red : C.surface, border: isMe ? "none" : "1px solid " + C.border,
                }}>
                  <div style={{ color: C.white, fontSize: 13, lineHeight: 1.4 }}>{m.text}</div>
                  <div style={{ color: isMe ? "rgba(255,255,255,0.5)" : C.dim, fontSize: 9, marginTop: 4, textAlign: "right" }}>{m.time}</div>
                </div>
              </div>
            );
          })}
        </div>
        <div style={{ padding: "10px 16px 14px", borderTop: "1px solid " + C.border, display: "flex", gap: 8, alignItems: "center" }}>
          <div style={{ flex: 1, display: "flex", alignItems: "center", gap: 8, background: C.surface, borderRadius: 14, padding: "10px 14px", border: "1px solid " + C.border }}>
            <input
              value={inputText}
              onChange={e => setInputText(e.target.value)}
              onKeyDown={e => e.key === "Enter" && handleSend()}
              placeholder="Type a message..."
              style={{ flex: 1, background: "none", border: "none", outline: "none", color: C.white, fontSize: 13, fontFamily: "inherit" }}
            />
            <Image size={18} color={C.dim} />
          </div>
          <button onClick={handleSend} style={{
            width: 40, height: 40, borderRadius: 12, border: "none", cursor: "pointer",
            background: inputText.trim() ? C.red : C.surface,
            display: "flex", alignItems: "center", justifyContent: "center",
          }}>
            <Send size={18} color={inputText.trim() ? C.white : C.dim} />
          </button>
        </div>
        {reschedule && <RescheduleModal person={reschedule} onClose={() => setReschedule(null)} onConfirm={(slotData) => handleScheduleConfirm(reschedule.name, slotData)} />}
        {cancelConfirm && (
          <div style={{ position: "absolute", inset: 0, zIndex: 50, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <div onClick={() => setCancelConfirm(null)} style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,0.6)" }} />
            <div style={{ position: "relative", background: C.darker, borderRadius: 20, padding: "24px", width: "80%", textAlign: "center" }}>
              <div style={{ color: C.white, fontSize: 15, fontWeight: 700, marginBottom: 6 }}>{getSchedStatus(cancelConfirm) === "scheduled" ? "Manage meeting" : "Manage meeting request"}</div>
              <div style={{ color: C.muted, fontSize: 12, marginBottom: 10 }}>{getSchedStatus(cancelConfirm) === "scheduled" ? "Meeting with" : "Pending request with"} {cancelConfirm}</div>
              {scheduleStatuses[cancelConfirm] && (
                <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 6, padding: "8px 12px", background: C.card, borderRadius: 10, marginBottom: 16 }}>
                  <Clock size={13} color={getSchedStatus(cancelConfirm) === "scheduled" ? C.green : C.amber} />
                  <span style={{ color: C.white, fontSize: 12, fontWeight: 600 }}>{scheduleStatuses[cancelConfirm].day} - {scheduleStatuses[cancelConfirm].time}</span>
                </div>
              )}
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                <div style={{ display: "flex", gap: 8 }}>
                  <button onClick={() => setCancelConfirm(null)} style={{ flex: 1, padding: "10px", borderRadius: 12, border: "1px solid " + C.border, cursor: "pointer", background: C.card, color: C.muted, fontSize: 13, fontWeight: 700 }}>Keep</button>
                  <button onClick={() => { const name = cancelConfirm; setCancelConfirm(null); setReschedule({ name, photo: chatData[name].photo, role: chatData[name].role, org: chatData[name].org }); }} style={{ flex: 1, padding: "10px", borderRadius: 12, border: "none", cursor: "pointer", background: C.amber + "20", color: C.amber, fontSize: 13, fontWeight: 700 }}>Reschedule</button>
                </div>
                <button onClick={() => { cancelAllMeetings(cancelConfirm); setCancelConfirm(null); }} style={{ width: "100%", padding: "12px", borderRadius: 12, border: "none", cursor: "pointer", background: C.red, color: C.white, fontSize: 14, fontWeight: 700 }}>{getSchedStatus(cancelConfirm) === "scheduled" ? "Cancel Meeting" : "Cancel Request"}</button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  // Chat list view with tabs
  return (
    <div style={{ display: "flex", flexDirection: "column", height: 812, position: "relative" }}>
      <StatusBar />
      <AppHeader title="Chat" right={<Avatar src={GUS} size={32} ring={C.red} />} />
      <div style={{ display: "flex", gap: 6, padding: "0 20px 12px" }}>
        {["connected", "requests"].map(t => (
          <button key={t} onClick={() => setChatTab(t)} style={{
            flex: 1, padding: "9px 0", borderRadius: 12, border: "none", cursor: "pointer",
            fontSize: 13, fontWeight: 700, textAlign: "center",
            background: chatTab === t ? C.red : C.surface, color: chatTab === t ? C.white : C.muted,
          }}>{t === "connected" ? `Connected (${chats.filter(c => hasIncomingPending(c.name)).length})` : `Requests (${CONNECTION_REQUESTS.filter(r => !connectionStatuses[r.name]).length})`}</button>
        ))}
      </div>
      {chatTab === "connected" && (
        <>
          <div style={{ flex: 1, overflowY: "auto", padding: "0 20px", WebkitOverflowScrolling: "touch" }} className="hide-scrollbar">
            {chats.map((c, i) => {
              const sched = getSchedStatus(c.name);
              const incoming = hasIncomingPending(c.name);
              const btnColor = sched === "scheduled" ? C.green : sched === "requested" ? (incoming ? C.red : C.amber) : C.dim;
              const btnBg = sched === "scheduled" ? C.green + "15" : sched === "requested" ? (incoming ? C.red + "15" : C.amber + "15") : C.surface;
              return (
                <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, padding: "14px 0", borderBottom: i < chats.length-1 ? "1px solid " + C.border : "none" }}>
                  <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 3 }}>
                    <button onClick={(e) => {
                      e.stopPropagation();
                      if (scheduleStatuses[c.name]) { setCancelConfirm(c.name); }
                      else { setReschedule({ name: c.name, photo: chatData[c.name].photo, role: chatData[c.name].role, org: chatData[c.name].org }); }
                    }} style={{
                      width: 34, height: 34, borderRadius: 10, border: "none", cursor: "pointer",
                      background: btnBg, display: "flex", alignItems: "center", justifyContent: "center", padding: 0,
                    }}>
                      <Calendar size={16} color={btnColor} />
                    </button>
                    {sched && <span style={{ fontSize: 8, fontWeight: 600, color: btnColor }}>{sched === "scheduled" ? "Booked" : (incoming ? "Respond" : "Pending")}</span>}
                  </div>
                  <div onClick={() => setActiveChat(c.name)} style={{ display: "flex", alignItems: "center", gap: 10, flex: 1, cursor: "pointer", minWidth: 0 }}>
                    <Avatar src={chatData[c.name].photo} size={44} />
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                        <span style={{ color: C.white, fontSize: 13, fontWeight: 700 }}>{c.name}</span>
                        <span style={{ color: C.dim, fontSize: 10 }}>{c.time}</span>
                      </div>
                      <div style={{ color: C.muted, fontSize: 10, marginTop: 1 }}>{chatData[c.name].role} - {chatData[c.name].org}</div>
                      <div style={{ color: C.dim, fontSize: 11, marginTop: 2, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{c.msg}</div>
                    </div>
                    {incoming ? <div style={{ background: C.red, borderRadius: 10, padding: "2px 7px", fontSize: 10, fontWeight: 800, color: C.white }}>1</div> : c.unread > 0 ? <div style={{ background: C.red, borderRadius: 10, padding: "2px 7px", fontSize: 10, fontWeight: 800, color: C.white }}>{c.unread}</div> : null}
                  </div>
                </div>
              );
            })}
          </div>
          {cancelConfirm && (
            <div style={{ position: "absolute", inset: 0, zIndex: 50, display: "flex", alignItems: "center", justifyContent: "center" }}>
              <div onClick={() => setCancelConfirm(null)} style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,0.6)" }} />
              <div style={{ position: "relative", background: C.darker, borderRadius: 20, padding: "24px", width: "80%", textAlign: "center" }}>
                <div style={{ color: C.white, fontSize: 15, fontWeight: 700, marginBottom: 6 }}>{getSchedStatus(cancelConfirm) === "scheduled" ? "Manage meeting" : "Manage meeting request"}</div>
                <div style={{ color: C.muted, fontSize: 12, marginBottom: 10 }}>{getSchedStatus(cancelConfirm) === "scheduled" ? "Meeting with" : "Pending request with"} {cancelConfirm}</div>
                {scheduleStatuses[cancelConfirm] && (
                  <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 6, padding: "8px 12px", background: C.card, borderRadius: 10, marginBottom: 16 }}>
                    <Clock size={13} color={getSchedStatus(cancelConfirm) === "scheduled" ? C.green : C.amber} />
                    <span style={{ color: C.white, fontSize: 12, fontWeight: 600 }}>{scheduleStatuses[cancelConfirm].day} - {scheduleStatuses[cancelConfirm].time}</span>
                  </div>
                )}
                <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                  <div style={{ display: "flex", gap: 8 }}>
                    <button onClick={() => setCancelConfirm(null)} style={{
                      flex: 1, padding: "10px", borderRadius: 12, border: "1px solid " + C.border, cursor: "pointer",
                      background: C.card, color: C.muted, fontSize: 13, fontWeight: 700,
                    }}>Keep</button>
                    <button onClick={() => { const name = cancelConfirm; setCancelConfirm(null); setReschedule({ name, photo: chatData[name].photo, role: chatData[name].role, org: chatData[name].org }); }} style={{
                      flex: 1, padding: "10px", borderRadius: 12, border: "none", cursor: "pointer",
                      background: C.amber + "20", color: C.amber, fontSize: 13, fontWeight: 700,
                    }}>Reschedule</button>
                  </div>
                  <button onClick={() => { cancelAllMeetings(cancelConfirm); setCancelConfirm(null); }} style={{
                    width: "100%", padding: "12px", borderRadius: 12, border: "none", cursor: "pointer",
                    background: C.red, color: C.white, fontSize: 14, fontWeight: 700,
                  }}>{getSchedStatus(cancelConfirm) === "scheduled" ? "Cancel Meeting" : "Cancel Request"}</button>
                </div>
              </div>
            </div>
          )}
        </>
      )}
      {chatTab === "requests" && (
        <div style={{ flex: 1, overflowY: "auto", padding: "0 20px", WebkitOverflowScrolling: "touch" }} className="hide-scrollbar">
          {CONNECTION_REQUESTS.filter(r => connectionStatuses[r.name] !== "removed").map((r, i) => {
            const status = connectionStatuses[r.name];
            return (
              <div key={i} style={{ background: C.surface, borderRadius: 16, padding: "14px", marginBottom: 10, border: "1px solid " + C.border }}>
                <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
                  <Avatar src={r.photo} size={48} />
                  <div style={{ flex: 1 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                      <div style={{ color: C.white, fontSize: 14, fontWeight: 700 }}>{r.name}</div>
                      <span style={{ color: C.dim, fontSize: 10 }}>{r.time}</span>
                    </div>
                    <div style={{ color: C.muted, fontSize: 11, marginTop: 1 }}>{r.role} - {r.org}</div>
                  </div>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 6, marginTop: 10, marginBottom: 10 }}>
                  <UserPlus size={13} color={C.pink} />
                  <span style={{ color: C.pink, fontSize: 12, fontWeight: 700 }}>Connection Request</span>
                </div>
                <div style={{ color: C.dim, fontSize: 12, lineHeight: 1.4 }}>"{r.note}"</div>
                {status === "accepted" ? (
                  <div style={{ display: "flex", gap: 6, marginTop: 12 }}>
                    <div style={{ flex: 1, padding: "9px 12px", borderRadius: 12, background: C.green + "15", textAlign: "center", display: "flex", alignItems: "center", justifyContent: "center", gap: 5 }}>
                      <Check size={14} color={C.green} />
                      <span style={{ color: C.green, fontSize: 12, fontWeight: 700 }}>Connected</span>
                    </div>
                    <button onClick={() => { setActiveChat(r.name); setChatTab("connected"); }} style={{
                      width: 42, height: 42, borderRadius: 12, border: "none", cursor: "pointer",
                      background: C.pink + "15", display: "flex", alignItems: "center", justifyContent: "center", padding: 0,
                    }}><MessageCircle size={18} color={C.pink} /></button>
                    <button onClick={() => setReschedule({ name: r.name, photo: r.photo, role: r.role, org: r.org })} style={{
                      width: 42, height: 42, borderRadius: 12, border: "none", cursor: "pointer",
                      background: C.red + "15", display: "flex", alignItems: "center", justifyContent: "center", padding: 0,
                    }}><Calendar size={18} color={C.red} /></button>
                  </div>
                ) : status === "declined" ? (
                  <div style={{ marginTop: 12, padding: "9px 12px", borderRadius: 10, background: C.red + "15", textAlign: "center" }}>
                    <span style={{ color: C.red, fontSize: 12, fontWeight: 700 }}>Declined</span>
                  </div>
                ) : (
                  <div style={{ display: "flex", gap: 6, marginTop: 12 }}>
                    <button onClick={() => handleConnectionAction(r.name, "declined")} style={{
                      width: 42, height: 42, borderRadius: 12, border: "1px solid " + C.border, cursor: "pointer",
                      background: C.card, display: "flex", alignItems: "center", justifyContent: "center", padding: 0,
                    }}><X size={18} color={C.muted} /></button>
                    <button onClick={() => handleConnectionAction(r.name, "accepted")} style={{
                      flex: 1, padding: "10px 0", borderRadius: 12, border: "none", cursor: "pointer",
                      background: C.green + "20", color: C.green, fontSize: 13, fontWeight: 700,
                      display: "flex", alignItems: "center", justifyContent: "center", gap: 5,
                    }}><Check size={15} /> Accept</button>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
      <TabBar active="chat" onNav={onNav} />
      {reschedule && <RescheduleModal person={reschedule} onClose={() => setReschedule(null)} onConfirm={(slotData) => handleScheduleConfirm(reschedule.name, slotData)} />}
    </div>
  );
};

// PROFILE SCREEN
const QRCode = ({ url, size = 120 }) => {
  const mods = [];
  const data = url || "https://beawhale.io";
  // Simple deterministic QR-like pattern from URL hash
  let hash = 0;
  for (let i = 0; i < data.length; i++) hash = ((hash << 5) - hash + data.charCodeAt(i)) | 0;
  const grid = 21;
  const cell = size / grid;
  // Finder patterns (top-left, top-right, bottom-left)
  const addFinder = (ox, oy) => {
    for (let r = 0; r < 7; r++) for (let c = 0; c < 7; c++) {
      if (r === 0 || r === 6 || c === 0 || c === 6 || (r >= 2 && r <= 4 && c >= 2 && c <= 4)) mods.push({ r: oy + r, c: ox + c });
    }
  };
  addFinder(0, 0); addFinder(14, 0); addFinder(0, 14);
  // Data modules from hash
  const seed = Math.abs(hash);
  for (let r = 0; r < grid; r++) for (let c = 0; c < grid; c++) {
    const inFinder = (r < 8 && c < 8) || (r < 8 && c > 12) || (r > 12 && c < 8);
    if (!inFinder) {
      const v = ((seed * (r * grid + c + 1) * 31) >> 3) & 1;
      if (v) mods.push({ r, c });
    }
  }
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <rect width={size} height={size} fill="white" rx={4} />
      {mods.map((m, i) => <rect key={i} x={m.c * cell} y={m.r * cell} width={cell} height={cell} fill="#1E1E2C" />)}
    </svg>
  );
};

